    expect(result.auditEvent.from).toBe("running");
    expect(result.auditEvent.to).toBe("paused");
    expect(result.auditEvent.action).toBe("pause");
  });

  it("rejects invalid transition", () => {
    const result = applyWorkflowTransition({
      entityType: "content_run",
      currentStatus: "queued",
      action: "pause",
      workflow: {
        entityId: "content-2"
      }
    });

    expect(result).toEqual(
      expect.objectContaining({
        ok: false,
        code: "invalid_transition"
      })
    );
  });

  it("enforces policy guard", () => {
    const policy: WorkflowPolicy = {
      name: "no-cancel-policy",
      guards: {
        cancel: () => ({ allowed: false, reason: "board-only action" })
      }
    };

    const result = applyWorkflowTransition({
      entityType: "content_run",
      currentStatus: "running",
      action: "cancel",
      workflow: {
        entityId: "content-3"
      },
      policy
    });

    expect(result).toEqual(
      expect.objectContaining({
        ok: false,
        code: "guard_blocked",
        message: "board-only action"
      })
    );
  });

  it("applies retry transition with reset effects", () => {
    const result = applyWorkflowTransition({
      entityType: "stage_run",
      currentStatus: "failed",
      action: "retry",
      workflow: {
        entityId: "stage-1"
      }
    });

    expect(result.ok).toBe(true);
    if (!result.ok) {
      return;
    }

    expect(result.to).toBe("queued");
    expect(result.effects).toEqual(
      expect.arrayContaining(["reset_attempts", "clear_failure_reason", "enqueue_execution"])
    );
  });

  it("applies rerun and supersede behavior", () => {
    const result = applyWorkflowTransition({
      entityType: "content_run",
      currentStatus: "completed",
      action: "rerun",
      workflow: {
        entityId: "content-4"
      }
    });

    expect(result.ok).toBe(true);
    if (!result.ok) {
      return;
    }

    expect(result.to).toBe("queued");
    expect(result.effects).toEqual(
      expect.arrayContaining([
        "create_new_version",
        "supersede_previous_version",
        "supersede_downstream_outputs"
      ])
    );
  });

  it("supports send_back from awaiting_approval", () => {
    const result = applyWorkflowTransition({
      entityType: "stage_run",
      currentStatus: "awaiting_approval",
      action: "send_back",
      workflow: {
        entityId: "stage-2"
      }
    });

    expect(result.ok).toBe(true);
    if (!result.ok) {
      return;
    }

    expect(result.to).toBe("awaiting_input");
    expect(result.effects).toContain("requires_input_revision");
  });

  it("emits audit event through hooks", () => {
    const hook = vi.fn();

    const result = applyWorkflowTransition({
      entityType: "stage_run",
      currentStatus: "awaiting_approval",
      action: "approve",
      workflow: {
        entityId: "stage-3",
        actorId: "reviewer-1"
      },
      auditHooks: [hook]
    });

    expect(result.ok).toBe(true);
    expect(hook).toHaveBeenCalledTimes(1);
    expect(hook).toHaveBeenCalledWith(
      expect.objectContaining({
        entityType: "stage_run",
        entityId: "stage-3",
        action: "approve",
        from: "awaiting_approval",
        to: "running"
      })
    );
  });
});

